text:
@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;600;800&display=swap');

:root {
    --bg-color: #f8fafc;
    --card-bg: #ffffff;
    --primary: #6366f1;
    --text-main: #1e293b;
    --text-muted: #64748b;
    --danger: #ef4444;
    --edit: #10b981;
    --border: #e2e8f0;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Plus Jakarta Sans', sans-serif;
    background-color: var(--bg-color);
    color: var(--text-main);
    padding: 40px 20px;
}

#container {
    max-width: 1100px;
    margin: 0 auto;
}

#headingEl {
    text-align: center;
    font-size: 2.5rem;
    margin-bottom: 40px;
    letter-spacing: -1.5px;
}

#noteForm {
    max-width: 500px;
    margin: 0 auto 50px;
    display: flex;
    background: white;
    padding: 6px;
    border-radius: 12px;
    border: 1px solid var(--border);
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
}

#noteInput {
    flex: 1; 
    border: none;
    outline: none;
    padding: 10px 15px;
    font-size: 1rem;
    resize: none; /* Prevents the user from manually resizing the box */
    font-family: inherit; /* Textareas don't always inherit body font */
    overflow-y: hidden; /* Keeps it looking like a single line until it grows */
}


#addNoteBtn {
    background: var(--primary);
    color: white;
    border: none;
    padding: 0 20px;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
}

#notesList {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 20px;
    list-style: none;
}

#notesList li {
    background: var(--card-bg);
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 20px;
    height: 220px; /* Slightly increased height for better reading */
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    transition: all 0.2s ease;
}

#notesList li:hover {
    border-color: var(--primary);
    box-shadow: 0 10px 20px rgba(0,0,0,0.04);
}

#notesList li span {
    font-size: 1rem;
    line-height: 1.5;
    color: var(--text-main);
    overflow-y: auto; /* Allows vertical scrolling for long text */
    word-break: break-word; /* Prevents long words from breaking layout */
    padding-right: 8px;
    margin-bottom: 10px;
}

/* Custom Thin Scrollbar for the notes */
#notesList li span::-webkit-scrollbar {
    width: 4px;
}

#notesList li span::-webkit-scrollbar-thumb {
    background: transparent; /* Hidden by default */
    border-radius: 10px;
}

#notesList li:hover span::-webkit-scrollbar-thumb {
    background: var(--border); /* Appears on hover for a cleaner look */
}

.note-actions {
    display: flex;
    justify-content: flex-end;
    gap: 8px;
    padding-top: 15px;
    border-top: 1px solid #f1f5f9;
    background: var(--card-bg); 
}

#edit-btn, #delete-btn {
    padding: 6px 12px;
    font-size: 11px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border-radius: 6px;
    border: 1px solid transparent;
    cursor: pointer;
    transition: all 0.2s;
}

#edit-btn {
    background: #f0fdf4;
    color: var(--edit);
}

#edit-btn:hover {
    background: var(--edit);
    color: white;
}

#delete-btn {
    background: #fef2f2;
    color: var(--danger);
}

#delete-btn:hover {
    background: var(--danger);
    color: white;
}

#notesList li span {
    white-space: pre-wrap; /* This ensures line breaks are actually rendered */

}
